<?php
declare(strict_types=1);
require_once __DIR__ . '/_merchant.php';
$method=strtoupper($_SERVER['REQUEST_METHOD']??'GET');$user=mg_require_permission($method==='GET'?'merchant.workspace.view':'merchant.team.manage');$pdo=mg_db();$workspace=mg_merchant_ensure_workspace($pdo,$user);
if($method==='GET'){$stmt=$pdo->prepare("SELECT public_id,user_id,display_name,role_key,location_scope_json,status,invited_at,accepted_at,updated_at FROM merchant_team_members WHERE workspace_id=? AND status<>'removed' ORDER BY FIELD(role_key,'owner','admin','manager','location_staff','claims_staff','analyst','viewer'),id");$stmt->execute([(int)$workspace['id']]);mg_ok(['members'=>$stmt->fetchAll()]);}
if($method!=='POST')mg_fail('Method not allowed.',405);$input=mg_input();mg_require_csrf_for_write($input);$email=strtolower(trim((string)($input['email']??'')));$role=trim((string)($input['role_key']??'viewer'));$roles=['admin','manager','location_staff','claims_staff','analyst','viewer'];if(!in_array($role,$roles,true))mg_fail('Invalid merchant team role.',422);$hash=mg_merchant_email_hash($email);$existing=$pdo->prepare("SELECT id FROM merchant_team_members WHERE workspace_id=? AND invited_email_hash=? AND status<>'removed' LIMIT 1");$existing->execute([(int)$workspace['id'],$hash]);if(!$existing->fetchColumn()){$seatUsage=$pdo->prepare("SELECT COUNT(*) FROM merchant_team_members WHERE workspace_id=? AND status<>'removed'");$seatUsage->execute([(int)$workspace['id']]);mg_package_require_limit_available($pdo,$user,'max_team_seats',(int)$seatUsage->fetchColumn(),'Team seat limit reached.');}$publicId=mg_merchant_uuid();$scope=mg_intelligence_json($input['location_scope']??null,32768);$pdo->prepare("INSERT INTO merchant_team_members (public_id,workspace_id,invited_email_hash,display_name,role_key,location_scope_json,status,invited_by_user_id,invited_at,created_at,updated_at) VALUES (?,?,?,?,?,?,'invited',?,NOW(),NOW(),NOW()) ON DUPLICATE KEY UPDATE role_key=VALUES(role_key),location_scope_json=VALUES(location_scope_json),status='invited',invited_by_user_id=VALUES(invited_by_user_id),invited_at=NOW(),updated_at=NOW()")
 ->execute([$publicId,(int)$workspace['id'],$hash,trim((string)($input['display_name']??''))?:null,$role,$scope,(int)$user['id']]);mg_audit('merchant.team_invited','merchant_workspace',['workspace_id'=>$workspace['public_id'],'role'=>$role],(int)$user['id']);mg_ok(['status'=>'invited','role_key'=>$role],'Team invitation recorded.',201);